// Enhanced Technical Indicators Calculation for Professional Trading
const candles = $node['Get 5Min Candles'].json.data;
const currentPrice = $node['Get Spot Price'].json.data.ltp;
const vix = $node['Get India VIX'].json.data.ltp;

// RSI Calculation (14 period)
function calculateRSI(prices, period = 14) {
  if (prices.length < period + 1) return 50; // Default neutral

  const gains = [];
  const losses = [];

  for (let i = 1; i < prices.length; i++) {
    const change = prices[i] - prices[i-1];
    gains.push(change > 0 ? change : 0);
    losses.push(change < 0 ? Math.abs(change) : 0);
  }

  const avgGain = gains.slice(-period).reduce((a, b) => a + b, 0) / period;
  const avgLoss = losses.slice(-period).reduce((a, b) => a + b, 0) / period;

  if (avgLoss === 0) return 100;
  const rs = avgGain / avgLoss;
  return 100 - (100 / (1 + rs));
}

// MACD Calculation
function calculateEMA(prices, period) {
  if (prices.length === 0) return 0;
  const k = 2 / (period + 1);
  let ema = prices[0];
  for (let i = 1; i < prices.length; i++) {
    ema = prices[i] * k + ema * (1 - k);
  }
  return ema;
}

function calculateMACD(prices) {
  if (prices.length < 26) return { macd: 0, signal: 0, histogram: 0 };

  const ema12 = calculateEMA(prices, 12);
  const ema26 = calculateEMA(prices, 26);
  const macd = ema12 - ema26;

  // For signal line, we'll use a simplified approach
  const macdLine = [macd];
  const signal = calculateEMA(macdLine, 9);

  return {
    macd: macd,
    signal: signal,
    histogram: macd - signal
  };
}

// Volume Ratio Calculation
function calculateVolumeRatio(candles) {
  if (candles.length < 20) return 1.0;

  const currentVolume = parseFloat(candles[candles.length - 1].volume);
  const avgVolume = candles.slice(-20).reduce((sum, candle) => 
    sum + parseFloat(candle.volume), 0) / 20;

  return avgVolume > 0 ? currentVolume / avgVolume : 1.0;
}

// Momentum Calculation
function calculateMomentum(prices, period = 10) {
  if (prices.length < period) return 0;
  const current = prices[prices.length - 1];
  const previous = prices[prices.length - period];
  return previous > 0 ? ((current - previous) / previous) * 100 : 0;
}

// Enhanced Candle Pattern Detection
function detectCandlePattern(candle) {
  const open = parseFloat(candle.open);
  const high = parseFloat(candle.high);
  const low = parseFloat(candle.low);
  const close = parseFloat(candle.close);

  const body = Math.abs(close - open);
  const upperShadow = high - Math.max(open, close);
  const lowerShadow = Math.min(open, close) - low;
  const totalRange = high - low;

  if (totalRange === 0) return "NORMAL";

  // Doji - Small body relative to range
  if (body < totalRange * 0.1) return "DOJI";

  // Hammer - Long lower shadow, small upper shadow
  if (lowerShadow > body * 2 && upperShadow < body * 0.5) return "HAMMER";

  // Shooting Star - Long upper shadow, small lower shadow
  if (upperShadow > body * 2 && lowerShadow < body * 0.5) return "SHOOTING_STAR";

  // Marubozu - Very small shadows
  if (upperShadow < totalRange * 0.05 && lowerShadow < totalRange * 0.05) return "MARUBOZU";

  // Engulfing patterns
  if (candles.length >= 2) {
    const prevCandle = candles[candles.length - 2];
    const prevOpen = parseFloat(prevCandle.open);
    const prevClose = parseFloat(prevCandle.close);

    // Bullish Engulfing
    if (prevClose < prevOpen && close > open && 
        close > prevOpen && open < prevClose) {
      return "BULLISH_ENGULFING";
    }

    // Bearish Engulfing
    if (prevClose > prevOpen && close < open && 
        close < prevOpen && open > prevClose) {
      return "BEARISH_ENGULFING";
    }
  }

  return "NORMAL";
}

// Market Strength Analysis
function analyzeMarketStrength(rsi, macd, momentum, volumeRatio) {
  let strength = 0;
  let signals = [];

  // RSI Analysis
  if (rsi < 30) {
    strength += 2;
    signals.push("RSI_OVERSOLD");
  } else if (rsi > 70) {
    strength -= 2;
    signals.push("RSI_OVERBOUGHT");
  }

  // MACD Analysis
  if (macd.macd > 0 && macd.histogram > 0) {
    strength += 1.5;
    signals.push("MACD_BULLISH");
  } else if (macd.macd < 0 && macd.histogram < 0) {
    strength -= 1.5;
    signals.push("MACD_BEARISH");
  }

  // Momentum Analysis
  if (momentum > 2) {
    strength += 1;
    signals.push("MOMENTUM_STRONG_BULLISH");
  } else if (momentum < -2) {
    strength -= 1;
    signals.push("MOMENTUM_STRONG_BEARISH");
  }

  // Volume Analysis
  if (volumeRatio > 1.5) {
    strength += 0.5;
    signals.push("VOLUME_SURGE");
  }

  return { strength, signals };
}

// Extract and calculate all indicators
const closePrices = candles.map(c => parseFloat(c.close));
const lastCandle = candles[candles.length - 1];

const rsi = calculateRSI(closePrices);
const macd = calculateMACD(closePrices);
const momentum = calculateMomentum(closePrices);
const volumeRatio = calculateVolumeRatio(candles);
const candlePattern = detectCandlePattern(lastCandle);
const marketAnalysis = analyzeMarketStrength(rsi, macd, momentum, volumeRatio);

// Get sentiment from previous node
const sentiment = $node['Market Sentiment API'].json.sentiment || 'NEUTRAL';

// Compile comprehensive indicators
const indicators = {
  // Basic Indicators
  rsi: Math.round(rsi * 100) / 100,
  macd: {
    macd: Math.round(macd.macd * 100) / 100,
    signal: Math.round(macd.signal * 100) / 100,
    histogram: Math.round(macd.histogram * 100) / 100
  },
  momentum: Math.round(momentum * 100) / 100,
  volumeRatio: Math.round(volumeRatio * 100) / 100,

  // Market Data
  spotPrice: currentPrice,
  vix: vix,
  sentiment: sentiment,
  candlePattern: candlePattern,

  // Analysis Results
  marketStrength: Math.round(marketAnalysis.strength * 100) / 100,
  detectedSignals: marketAnalysis.signals,
  signalCount: marketAnalysis.signals.length,

  // Market Conditions
  volatilityRegime: vix > 20 ? "HIGH" : vix > 15 ? "MEDIUM" : "LOW",
  trendDirection: marketAnalysis.strength > 1 ? "BULLISH" : 
                  marketAnalysis.strength < -1 ? "BEARISH" : "SIDEWAYS",

  // Additional Context
  timestamp: new Date().toISOString(),
  candleCount: candles.length,
  priceChange: closePrices.length > 1 ? 
    Math.round(((closePrices[closePrices.length - 1] - closePrices[closePrices.length - 2]) / 
    closePrices[closePrices.length - 2]) * 10000) / 100 : 0
};

return { indicators };

// Enhanced Writers Zone Detection with Professional Analysis
const ceOptionChain = $node['Get Option Chain CE'].json.data || [];
const peOptionChain = $node['Get Option Chain PE'].json.data || [];
const currentPrice = $node['Get Spot Price'].json.data.ltp;
const spotPrice = parseFloat(currentPrice);

// Initialize analysis variables
let maxCEOI = 0;
let maxPEOI = 0;
let maxCEStrike = 0;
let maxPEStrike = 0;
let totalCEOI = 0;
let totalPEOI = 0;

// Arrays to store OI data for detailed analysis
const ceOIData = [];
const peOIData = [];
const significantLevels = [];

// Process CE Option Chain
ceOptionChain.forEach(option => {
  const strike = parseFloat(option.strikeprice || 0);
  const oi = parseFloat(option.openinterest || 0);
  const volume = parseFloat(option.volume || 0);

  if (strike > 0 && oi > 0) {
    ceOIData.push({ strike, oi, volume, type: 'CE' });
    totalCEOI += oi;

    if (oi > maxCEOI) {
      maxCEOI = oi;
      maxCEStrike = strike;
    }
  }
});

// Process PE Option Chain
peOptionChain.forEach(option => {
  const strike = parseFloat(option.strikeprice || 0);
  const oi = parseFloat(option.openinterest || 0);
  const volume = parseFloat(option.volume || 0);

  if (strike > 0 && oi > 0) {
    peOIData.push({ strike, oi, volume, type: 'PE' });
    totalPEOI += oi;

    if (oi > maxPEOI) {
      maxPEOI = oi;
      maxPEStrike = strike;
    }
  }
});

// Calculate Put-Call Ratio
const putCallRatio = totalCEOI > 0 ? totalPEOI / totalCEOI : 1.0;

// Find significant support and resistance levels
const ceThreshold = maxCEOI * 0.6; // 60% of max CE OI
const peThreshold = maxPEOI * 0.6; // 60% of max PE OI

const significantCELevels = ceOIData
  .filter(item => item.oi >= ceThreshold)
  .map(item => item.strike)
  .sort((a, b) => a - b);

const significantPELevels = peOIData
  .filter(item => item.oi >= peThreshold)
  .map(item => item.strike)
  .sort((a, b) => a - b);

// Professional Writers Zone Analysis
function analyzeWritersZone() {
  let analysis = {
    zone: 'NEUTRAL',
    confidence: 0,
    reasoning: [],
    supportLevels: [],
    resistanceLevels: [],
    marketStructure: 'BALANCED'
  };

  // Primary Analysis: Price position relative to max OI strikes
  const distanceFromCEStrike = Math.abs(spotPrice - maxCEStrike);
  const distanceFromPEStrike = Math.abs(spotPrice - maxPEStrike);

  // Zone determination based on price position
  if (spotPrice > maxCEStrike && spotPrice > maxPEStrike) {
    analysis.zone = 'BULLISH';
    analysis.confidence += 0.4;
    analysis.reasoning.push('Price trading above both max CE and PE OI strikes');
  } else if (spotPrice < maxCEStrike && spotPrice < maxPEStrike) {
    analysis.zone = 'BEARISH';
    analysis.confidence += 0.4;
    analysis.reasoning.push('Price trading below both max CE and PE OI strikes');
  } else {
    analysis.reasoning.push('Price between max CE and PE OI strikes - mixed signals');
  }

  // Put-Call Ratio Analysis
  if (putCallRatio > 1.3) {
    analysis.marketStructure = 'PUT_HEAVY';
    if (analysis.zone === 'BEARISH') {
      analysis.confidence += 0.3;
      analysis.reasoning.push('High Put-Call ratio confirms bearish sentiment');
    } else if (analysis.zone === 'NEUTRAL') {
      analysis.zone = 'BEARISH';
      analysis.confidence += 0.2;
      analysis.reasoning.push('High Put-Call ratio suggests bearish bias');
    }
  } else if (putCallRatio < 0.7) {
    analysis.marketStructure = 'CALL_HEAVY';
    if (analysis.zone === 'BULLISH') {
      analysis.confidence += 0.3;
      analysis.reasoning.push('Low Put-Call ratio confirms bullish sentiment');
    } else if (analysis.zone === 'NEUTRAL') {
      analysis.zone = 'BULLISH';
      analysis.confidence += 0.2;
      analysis.reasoning.push('Low Put-Call ratio suggests bullish bias');
    }
  } else {
    analysis.marketStructure = 'BALANCED';
    analysis.reasoning.push('Balanced Put-Call ratio indicates neutral sentiment');
  }

  // Distance Analysis - closer to which max OI
  if (distanceFromPEStrike < distanceFromCEStrike) {
    analysis.confidence += 0.1;
    analysis.reasoning.push('Price closer to PE max OI (potential support)');
    analysis.supportLevels.push(maxPEStrike);
  } else if (distanceFromCEStrike < distanceFromPEStrike) {
    analysis.confidence += 0.1;
    analysis.reasoning.push('Price closer to CE max OI (potential resistance)');
    analysis.resistanceLevels.push(maxCEStrike);
  }

  // OI Concentration Analysis
  const oiConcentration = (maxCEOI + maxPEOI) / (totalCEOI + totalPEOI);
  if (oiConcentration > 0.3) {
    analysis.confidence += 0.1;
    analysis.reasoning.push('High OI concentration at key strikes');
  }

  // Volume Analysis
  const ceVolumeAtMaxOI = ceOIData.find(item => item.strike === maxCEStrike)?.volume || 0;
  const peVolumeAtMaxOI = peOIData.find(item => item.strike === maxPEStrike)?.volume || 0;

  if (ceVolumeAtMaxOI > peVolumeAtMaxOI * 1.5) {
    analysis.reasoning.push('Higher CE volume at max OI strike');
  } else if (peVolumeAtMaxOI > ceVolumeAtMaxOI * 1.5) {
    analysis.reasoning.push('Higher PE volume at max OI strike');
  }

  // Add significant levels to support/resistance
  significantPELevels.forEach(level => {
    if (level <= spotPrice) analysis.supportLevels.push(level);
  });

  significantCELevels.forEach(level => {
    if (level >= spotPrice) analysis.resistanceLevels.push(level);
  });

  // Remove duplicates and sort
  analysis.supportLevels = [...new Set(analysis.supportLevels)].sort((a, b) => b - a);
  analysis.resistanceLevels = [...new Set(analysis.resistanceLevels)].sort((a, b) => a - b);

  // Final confidence adjustment
  analysis.confidence = Math.min(analysis.confidence, 1.0);

  // If confidence is too low, default to NEUTRAL
  if (analysis.confidence < 0.3) {
    analysis.zone = 'NEUTRAL';
    analysis.reasoning.push('Insufficient conviction for directional bias');
  }

  return analysis;
}

// Perform the analysis
const writersAnalysis = analyzeWritersZone();

// Compile comprehensive results
const result = {
  // Primary Results
  writersZone: writersAnalysis.zone,
  confidence: Math.round(writersAnalysis.confidence * 100) / 100,

  // OI Data
  maxCEOI: maxCEOI,
  maxPEOI: maxPEOI,
  maxCEStrike: maxCEStrike,
  maxPEStrike: maxPEStrike,
  totalCEOI: totalCEOI,
  totalPEOI: totalPEOI,
  putCallRatio: Math.round(putCallRatio * 100) / 100,

  // Significant Levels
  significantCELevels: significantCELevels,
  significantPELevels: significantPELevels,
  supportLevels: writersAnalysis.supportLevels.slice(0, 3), // Top 3
  resistanceLevels: writersAnalysis.resistanceLevels.slice(0, 3), // Top 3

  // Analysis Details
  reasoning: writersAnalysis.reasoning,
  marketStructure: writersAnalysis.marketStructure,

  // Market Context
  currentPrice: spotPrice,
  distanceFromCEStrike: Math.round(Math.abs(spotPrice - maxCEStrike)),
  distanceFromPEStrike: Math.round(Math.abs(spotPrice - maxPEStrike)),

  // Statistics
  ceOptionsCount: ceOIData.length,
  peOptionsCount: peOIData.length,
  oiConcentration: Math.round(((maxCEOI + maxPEOI) / (totalCEOI + totalPEOI)) * 100) / 100,

  // Timestamp
  timestamp: new Date().toISOString()
};

return result;

// Enhanced Strike Price Calculation with Live Symbol Token Fetching
const signal = $node['AI Trade Confirmation'].json.signal;
const spotPrice = $node['Get Spot Price'].json.data.ltp;
const jwtToken = $node['Angel One Login'].json.data.jwtToken;
const baseStrike = Math.round(spotPrice / 100) * 100;

let targetStrike;
let optionType;
let lotSize;

// Determine option type and strike based on signal
if (signal === 'BUY_CE') {
  targetStrike = baseStrike; // ATM Call
  optionType = 'CE';
} else if (signal === 'BUY_PE') {
  targetStrike = baseStrike; // ATM Put
  optionType = 'PE';
} else {
  throw new Error('Invalid signal: ' + signal);
}

// Set lot size based on underlying
const underlying = 'BANKNIFTY';
lotSize = underlying === 'BANKNIFTY' ? 25 : 50; // NIFTY = 50

// Calculate next Thursday expiry
const today = new Date();
const nextThursday = new Date(today);
const daysUntilThursday = (4 - today.getDay() + 7) % 7;

if (daysUntilThursday === 0 && today.getHours() >= 15) {
  // If it's Thursday after 3 PM, get next Thursday
  nextThursday.setDate(today.getDate() + 7);
} else {
  nextThursday.setDate(today.getDate() + daysUntilThursday);
}

// Format expiry date for symbol (DDMMMYY format)
const months = ['JAN', 'FEB', 'MAR', 'APR', 'MAY', 'JUN', 'JUL', 'AUG', 'SEP', 'OCT', 'NOV', 'DEC'];
const day = String(nextThursday.getDate()).padStart(2, '0');
const month = months[nextThursday.getMonth()];
const year = String(nextThursday.getFullYear()).slice(-2);
const expiryFormat = `${day}${month}${year}`;

// Create trading symbol in Angel One format
const tradingSymbol = `BANKNIFTY${expiryFormat}${targetStrike}${optionType}`;

// Fetch live symbol token from Angel One Search Scrip API
let symbolToken = "218057"; // Default fallback

try {
  const searchResponse = await fetch('https://apiconnect.angelbroking.com/rest/secure/angelbroking/order/v1/searchscrip', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': `Bearer ${jwtToken}`,
      'X-PrivateKey': process.env.ANGEL_API_KEY,
      'X-UserType': 'USER',
      'X-SourceID': 'WEB',
      'X-ClientLocalIP': '192.168.1.1',
      'X-ClientPublicIP': '106.193.147.98',
      'X-MACAddress': 'fe80::216:3eff:fe4e:9729'
    },
    body: JSON.stringify({
      exchange: 'NFO',
      searchscrip: tradingSymbol
    })
  });

  if (searchResponse.ok) {
    const searchData = await searchResponse.json();
    if (searchData.status && searchData.data && searchData.data.length > 0) {
      symbolToken = searchData.data[0].symboltoken;
      console.log(`Found live symbol token: ${symbolToken} for ${tradingSymbol}`);
    } else {
      console.warn(`Symbol not found: ${tradingSymbol}, using fallback token`);
    }
  } else {
    console.warn(`Search API failed, using fallback token for ${tradingSymbol}`);
  }
} catch (error) {
  console.error(`Error fetching symbol token: ${error.message}, using fallback`);
}

// Return complete order object in exact required format
return {
  "variety": "NORMAL",
  "tradingsymbol": tradingSymbol,
  "symboltoken": symbolToken,
  "transactiontype": "BUY",
  "exchange": "NFO",
  "ordertype": "MARKET",
  "producttype": "INTRADAY",
  "duration": "DAY",
  "price": "0",
  "quantity": lotSize.toString()
};

// Enhanced Calculate SL & Target Levels with Complete Order Objects
const orderBook = $node['Get Entry Fill Price'].json.data;
const entryOrderId = $node['Place Entry Market Order'].json.data.orderid;
const symbolToken = $node['Calculate Strike Price & Order Object'].json.symboltoken;

// Find the specific entry order in order book
const entryOrder = orderBook.find(order => order.orderid === entryOrderId);

if (!entryOrder) {
  throw new Error(`Entry order not found in order book. Order ID: ${entryOrderId}`);
}

// Validate entry order is executed
if (entryOrder.orderstatus !== 'complete' && entryOrder.orderstatus !== 'executed') {
  throw new Error(`Entry order not executed. Status: ${entryOrder.orderstatus}`);
}

// Get fill details
const fillPrice = parseFloat(entryOrder.averageprice || entryOrder.price);
const symbol = entryOrder.tradingsymbol;
const quantity = entryOrder.quantity;

// Validate fill price
if (!fillPrice || fillPrice <= 0) {
  throw new Error(`Invalid fill price: ${fillPrice}`);
}

// Calculate SL and Target levels
const stopLossPrice = fillPrice - 15;  // 15 points below entry
const targetPrice = fillPrice + 30;    // 30 points above entry

// Apply minimum value validation
const finalStopLoss = Math.max(stopLossPrice, 0.5); // Minimum SL of 0.5
const finalTarget = Math.max(targetPrice, fillPrice + 5); // Minimum target 5 points above entry

// Create Stop Loss Order Object in exact required format
const stopLossOrder = {
  "variety": "NORMAL",
  "tradingsymbol": symbol,
  "symboltoken": symbolToken,
  "transactiontype": "SELL",
  "exchange": "NFO",
  "ordertype": "SL-M",
  "producttype": "INTRADAY",
  "duration": "DAY",
  "price": "0",
  "triggerprice": finalStopLoss.toString(),
  "quantity": quantity
};

// Create Target Order Object in exact required format
const targetOrder = {
  "variety": "NORMAL",
  "tradingsymbol": symbol,
  "symboltoken": symbolToken,
  "transactiontype": "SELL",
  "exchange": "NFO",
  "ordertype": "LIMIT",
  "producttype": "INTRADAY",
  "duration": "DAY",
  "price": finalTarget.toString(),
  "quantity": quantity
};

// Return complete data object with order objects ready for API calls
return {
  // Entry order details
  entryOrderId: entryOrderId,
  symbol: symbol,
  symbolToken: symbolToken,
  quantity: quantity,
  fillPrice: fillPrice,

  // Calculated levels
  stopLoss: finalStopLoss,
  target: finalTarget,
  timestamp: new Date().toISOString(),

  // Complete order objects (ready for API calls)
  stopLossOrder: stopLossOrder,
  targetOrder: targetOrder,

  // Risk metrics
  riskAmount: fillPrice - finalStopLoss,
  rewardAmount: finalTarget - fillPrice,
  riskRewardRatio: Math.round(((finalTarget - fillPrice) / (fillPrice - finalStopLoss)) * 100) / 100,

  // Additional info for logging
  calculationDetails: {
    originalStopLoss: stopLossPrice,
    originalTarget: targetPrice,
    appliedMinimums: {
      stopLoss: finalStopLoss !== stopLossPrice,
      target: finalTarget !== targetPrice
    },
    entryOrderStatus: entryOrder.orderstatus,
    executionTime: entryOrder.updatetime || entryOrder.ordertime
  }
};
